const input = $input.first().json;
const action = input.action || 'list_articles';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.lexware&cred_key=eq.lexware_api_token&select=cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'Lexware API token not configured. Use add_credential to set it up.' } }];
}

const token = creds[0].cred_value;
const baseUrl = 'https://api.lexware.io/v1';
const headers = {
  'Authorization': 'Bearer ' + token,
  'Accept': 'application/json'
};
const jsonHeaders = {
  ...headers,
  'Content-Type': 'application/json'
};

function formatDate(dateStr) {
  if (!dateStr) return '';
  return dateStr.split('T')[0];
}

function formatCurrency(amount) {
  if (amount === undefined || amount === null) return '0.00';
  return Number(amount).toFixed(2);
}

// === list_articles ===
if (action === 'list_articles') {
  const page = input.page || '0';
  const type = input.type || '';
  try {
    let url = baseUrl + '/articles?page=' + page + '&size=25';
    if (type) url += '&type=' + type;
    const data = await helpers.httpRequest({ method: 'GET', url, headers });
    if (!data.content || data.content.length === 0) {
      return [{ json: { result: 'No articles found.' } }];
    }
    let result = 'Articles (page ' + data.number + ' of ' + data.totalPages + ', ' + data.totalElements + ' total):\n\n';
    for (const a of data.content) {
      result += '**' + a.title + '**';
      if (a.articleNumber) result += ' (#' + a.articleNumber + ')';
      result += '\n';
      result += '  Type: ' + a.type;
      if (a.unitName) result += ' | Unit: ' + a.unitName;
      result += '\n';
      if (a.price) {
        const p = a.price;
        result += '  Price: ' + formatCurrency(p.netPrice) + ' net';
        if (p.grossPrice) result += ' / ' + formatCurrency(p.grossPrice) + ' gross';
        result += ' (Tax: ' + (p.taxRate || 0) + '%)\n';
      }
      result += '  ID: ' + a.id + '\n\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list articles: ' + err.message } }];
  }

// === get_article ===
} else if (action === 'get_article') {
  const id = input.id;
  if (!id) return [{ json: { error: 'Parameter "id" is required.' } }];
  try {
    const a = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/articles/' + id, headers });
    let result = '**' + a.title + '**';
    if (a.articleNumber) result += ' (#' + a.articleNumber + ')';
    result += '\n';
    result += 'Type: ' + a.type + '\n';
    if (a.description) result += 'Description: ' + a.description + '\n';
    if (a.unitName) result += 'Unit: ' + a.unitName + '\n';
    if (a.price) {
      const p = a.price;
      result += 'Net Price: ' + formatCurrency(p.netPrice) + '\n';
      result += 'Gross Price: ' + formatCurrency(p.grossPrice) + '\n';
      result += 'Leading Price: ' + p.leadingPrice + '\n';
      result += 'Tax Rate: ' + (p.taxRate || 0) + '%\n';
    }
    if (a.gtin) result += 'GTIN: ' + a.gtin + '\n';
    result += 'Version: ' + a.version + '\n';
    result += 'ID: ' + a.id + '\n';
    result += 'Created: ' + formatDate(a.createdDate) + '\n';
    result += 'Updated: ' + formatDate(a.updatedDate) + '\n';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get article: ' + err.message } }];
  }

// === create_article ===
} else if (action === 'create_article') {
  const title = input.title;
  if (!title) return [{ json: { error: 'Parameter "title" is required.' } }];
  try {
    const body = {
      title: title,
      type: input.type || 'SERVICE',
      unitName: input.unitName || 'Stück',
      price: {
        netPrice: parseFloat(input.netPrice || '0'),
        taxRate: parseFloat(input.taxRate || '19'),
        leadingPrice: input.leadingPrice || 'net'
      }
    };
    if (input.description) body.description = input.description;
    if (input.articleNumber) body.articleNumber = input.articleNumber;
    if (input.gtin) body.gtin = input.gtin;
    const data = await helpers.httpRequest({
      method: 'POST',
      url: baseUrl + '/articles',
      headers: jsonHeaders,
      body: JSON.stringify(body)
    });
    return [{ json: { result: 'Article created successfully.\nID: ' + data.id + '\nResource: ' + data.resourceUri } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create article: ' + err.message } }];
  }

// === update_article ===
} else if (action === 'update_article') {
  const id = input.id;
  const version = input.version;
  if (!id || !version) return [{ json: { error: 'Parameters "id" and "version" are required. Use get_article first to get the current version.' } }];
  try {
    const body = {
      version: parseInt(version),
      title: input.title,
      type: input.type || 'SERVICE',
      unitName: input.unitName || 'Stück',
      price: {
        netPrice: parseFloat(input.netPrice || '0'),
        taxRate: parseFloat(input.taxRate || '19'),
        leadingPrice: input.leadingPrice || 'net'
      }
    };
    if (input.description) body.description = input.description;
    if (input.articleNumber) body.articleNumber = input.articleNumber;
    if (input.gtin) body.gtin = input.gtin;
    const data = await helpers.httpRequest({
      method: 'PUT',
      url: baseUrl + '/articles/' + id,
      headers: jsonHeaders,
      body: JSON.stringify(body)
    });
    return [{ json: { result: 'Article updated successfully.\nID: ' + data.id + '\nNew Version: ' + data.version } }];
  } catch (err) {
    return [{ json: { error: 'Failed to update article: ' + err.message } }];
  }

// === delete_article ===
} else if (action === 'delete_article') {
  const id = input.id;
  if (!id) return [{ json: { error: 'Parameter "id" is required.' } }];
  try {
    await helpers.httpRequest({ method: 'DELETE', url: baseUrl + '/articles/' + id, headers });
    return [{ json: { result: 'Article deleted successfully. ID: ' + id } }];
  } catch (err) {
    return [{ json: { error: 'Failed to delete article: ' + err.message } }];
  }

// === list_quotations ===
} else if (action === 'list_quotations') {
  const page = input.page || '0';
  const status = input.status || '';
  try {
    let url = baseUrl + '/voucherlist?voucherType=quotation&page=' + page + '&size=25&sort=voucherDate,DESC';
    if (status) url += '&voucherStatus=' + status;
    const data = await helpers.httpRequest({ method: 'GET', url, headers });
    if (!data.content || data.content.length === 0) {
      return [{ json: { result: 'No quotations found.' } }];
    }
    let result = 'Quotations (page ' + data.number + ' of ' + data.totalPages + ', ' + data.totalElements + ' total):\n\n';
    for (const q of data.content) {
      result += '**' + (q.voucherNumber || 'Draft') + '**';
      result += ' — ' + (q.contactName || 'Unknown contact') + '\n';
      result += '  Date: ' + formatDate(q.voucherDate);
      result += ' | Status: ' + q.voucherStatus;
      result += ' | Total: ' + formatCurrency(q.totalAmount) + '\n';
      result += '  ID: ' + q.id + '\n\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list quotations: ' + err.message } }];
  }

// === get_quotation ===
} else if (action === 'get_quotation') {
  const id = input.id;
  if (!id) return [{ json: { error: 'Parameter "id" is required.' } }];
  try {
    const q = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/quotations/' + id, headers });
    let result = '**Quotation';
    if (q.voucherNumber) result += ' ' + q.voucherNumber;
    result += '**\n';
    if (q.address) {
      if (q.address.name) result += 'To: ' + q.address.name + '\n';
      if (q.address.street) result += '  ' + q.address.street + '\n';
      if (q.address.zip || q.address.city) result += '  ' + (q.address.zip || '') + ' ' + (q.address.city || '') + '\n';
    }
    result += 'Date: ' + formatDate(q.voucherDate) + '\n';
    if (q.expirationDate) result += 'Expires: ' + formatDate(q.expirationDate) + '\n';
    result += '\nLine Items:\n';
    if (q.lineItems) {
      for (const item of q.lineItems) {
        if (item.type === 'custom') {
          result += '  - ' + item.name;
          if (item.quantity) result += ' (x' + item.quantity + ')';
          if (item.unitPrice && item.unitPrice.netAmount !== undefined) result += ' @ ' + formatCurrency(item.unitPrice.netAmount);
          result += '\n';
          if (item.description) result += '    ' + item.description + '\n';
        }
      }
    }
    if (q.totalPrice) {
      result += '\nTotal Net: ' + formatCurrency(q.totalPrice.totalNetAmount) + '\n';
      result += 'Total Gross: ' + formatCurrency(q.totalPrice.totalGrossAmount) + '\n';
      result += 'Tax: ' + formatCurrency(q.totalPrice.totalTaxAmount) + '\n';
    }
    result += '\nID: ' + q.id + '\n';
    result += 'Deep Link: https://app.lexware.de/permalink/quotations/view/' + q.id + '\n';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get quotation: ' + err.message } }];
  }

// === create_quotation ===
} else if (action === 'create_quotation') {
  const contactId = input.contactId || '';
  const voucherDate = input.voucherDate || new Date().toISOString().split('T')[0];
  const lineItemsStr = input.lineItems;
  if (!lineItemsStr) return [{ json: { error: 'Parameter "lineItems" is required. Provide as JSON array, e.g. [{"name":"Service","quantity":1,"unitPrice":100,"taxRate":19}]' } }];
  try {
    let lineItemsRaw;
    try { lineItemsRaw = JSON.parse(lineItemsStr); } catch(e) { return [{ json: { error: 'lineItems must be valid JSON: ' + e.message } }]; }
    const lineItems = lineItemsRaw.map(item => ({
      type: 'custom',
      name: item.name,
      quantity: item.quantity || 1,
      unitName: item.unitName || 'Stück',
      unitPrice: {
        currency: 'EUR',
        netAmount: item.unitPrice || item.netAmount || 0,
        taxRatePercentage: item.taxRate || item.taxRatePercentage || 19
      }
    }));
    const body = {
      voucherDate: voucherDate,
      lineItems: lineItems,
      totalPrice: { currency: 'EUR' },
      taxConditions: { taxType: 'net' }
    };
    if (contactId) body.address = { contactId: contactId };
    if (input.introduction) body.introduction = input.introduction;
    if (input.remark) body.remark = input.remark;
    if (input.expirationDate) body.expirationDate = input.expirationDate;
    const finalize = input.finalize === 'true' || input.finalize === true;
    let url = baseUrl + '/quotations';
    if (finalize) url += '?finalize=true';
    const data = await helpers.httpRequest({
      method: 'POST',
      url: url,
      headers: jsonHeaders,
      body: JSON.stringify(body)
    });
    let result = 'Quotation created successfully.';
    if (finalize) result += ' (finalized)';
    result += '\nID: ' + data.id;
    result += '\nResource: ' + data.resourceUri;
    result += '\nDeep Link: https://app.lexware.de/permalink/quotations/edit/' + data.id;
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create quotation: ' + err.message } }];
  }

// === list_invoices ===
} else if (action === 'list_invoices') {
  const page = input.page || '0';
  const status = input.status || '';
  try {
    let url = baseUrl + '/voucherlist?voucherType=invoice&page=' + page + '&size=25&sort=voucherDate,DESC';
    if (status) url += '&voucherStatus=' + status;
    const data = await helpers.httpRequest({ method: 'GET', url, headers });
    if (!data.content || data.content.length === 0) {
      return [{ json: { result: 'No invoices found.' } }];
    }
    let result = 'Invoices (page ' + data.number + ' of ' + data.totalPages + ', ' + data.totalElements + ' total):\n\n';
    for (const inv of data.content) {
      result += '**' + (inv.voucherNumber || 'Draft') + '**';
      result += ' — ' + (inv.contactName || 'Unknown contact') + '\n';
      result += '  Date: ' + formatDate(inv.voucherDate);
      result += ' | Status: ' + inv.voucherStatus;
      result += ' | Total: ' + formatCurrency(inv.totalAmount) + '\n';
      if (inv.dueDate) result += '  Due: ' + formatDate(inv.dueDate) + '\n';
      result += '  ID: ' + inv.id + '\n\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list invoices: ' + err.message } }];
  }

// === get_invoice ===
} else if (action === 'get_invoice') {
  const id = input.id;
  if (!id) return [{ json: { error: 'Parameter "id" is required.' } }];
  try {
    const inv = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/invoices/' + id, headers });
    let result = '**Invoice';
    if (inv.voucherNumber) result += ' ' + inv.voucherNumber;
    result += '**\n';
    if (inv.address) {
      if (inv.address.name) result += 'To: ' + inv.address.name + '\n';
      if (inv.address.street) result += '  ' + inv.address.street + '\n';
      if (inv.address.zip || inv.address.city) result += '  ' + (inv.address.zip || '') + ' ' + (inv.address.city || '') + '\n';
    }
    result += 'Date: ' + formatDate(inv.voucherDate) + '\n';
    if (inv.dueDate) result += 'Due: ' + formatDate(inv.dueDate) + '\n';
    result += '\nLine Items:\n';
    if (inv.lineItems) {
      for (const item of inv.lineItems) {
        if (item.type === 'custom') {
          result += '  - ' + item.name;
          if (item.quantity) result += ' (x' + item.quantity + ')';
          if (item.unitPrice && item.unitPrice.netAmount !== undefined) result += ' @ ' + formatCurrency(item.unitPrice.netAmount);
          result += '\n';
          if (item.description) result += '    ' + item.description + '\n';
        }
      }
    }
    if (inv.totalPrice) {
      result += '\nTotal Net: ' + formatCurrency(inv.totalPrice.totalNetAmount) + '\n';
      result += 'Total Gross: ' + formatCurrency(inv.totalPrice.totalGrossAmount) + '\n';
      result += 'Tax: ' + formatCurrency(inv.totalPrice.totalTaxAmount) + '\n';
    }
    if (inv.paymentConditions) {
      result += '\nPayment: ' + inv.paymentConditions.paymentTermLabel + '\n';
    }
    result += '\nID: ' + inv.id + '\n';
    result += 'Deep Link: https://app.lexware.de/permalink/invoices/view/' + inv.id + '\n';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get invoice: ' + err.message } }];
  }

// === create_invoice ===
} else if (action === 'create_invoice') {
  const contactId = input.contactId || '';
  const voucherDate = input.voucherDate || new Date().toISOString().split('T')[0];
  const lineItemsStr = input.lineItems;
  if (!lineItemsStr) return [{ json: { error: 'Parameter "lineItems" is required. Provide as JSON array, e.g. [{"name":"Service","quantity":1,"unitPrice":100,"taxRate":19}]' } }];
  try {
    let lineItemsRaw;
    try { lineItemsRaw = JSON.parse(lineItemsStr); } catch(e) { return [{ json: { error: 'lineItems must be valid JSON: ' + e.message } }]; }
    const lineItems = lineItemsRaw.map(item => ({
      type: 'custom',
      name: item.name,
      quantity: item.quantity || 1,
      unitName: item.unitName || 'Stück',
      unitPrice: {
        currency: 'EUR',
        netAmount: item.unitPrice || item.netAmount || 0,
        taxRatePercentage: item.taxRate || item.taxRatePercentage || 19
      }
    }));
    const body = {
      voucherDate: voucherDate,
      lineItems: lineItems,
      totalPrice: { currency: 'EUR' },
      taxConditions: { taxType: 'net' },
      shippingConditions: { shippingType: 'none' }
    };
    if (contactId) body.address = { contactId: contactId };
    if (input.introduction) body.introduction = input.introduction;
    if (input.remark) body.remark = input.remark;
    const finalize = input.finalize === 'true' || input.finalize === true;
    let url = baseUrl + '/invoices';
    if (finalize) url += '?finalize=true';
    const data = await helpers.httpRequest({
      method: 'POST',
      url: url,
      headers: jsonHeaders,
      body: JSON.stringify(body)
    });
    let result = 'Invoice created successfully.';
    if (finalize) result += ' (finalized)';
    result += '\nID: ' + data.id;
    result += '\nResource: ' + data.resourceUri;
    result += '\nDeep Link: https://app.lexware.de/permalink/invoices/edit/' + data.id;
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create invoice: ' + err.message } }];
  }

// === create_invoice_from_quotation ===
} else if (action === 'create_invoice_from_quotation') {
  const quotationId = input.quotation_id;
  if (!quotationId) return [{ json: { error: 'Parameter "quotation_id" is required.' } }];
  try {
    const finalize = input.finalize === 'true' || input.finalize === true;
    let url = baseUrl + '/invoices?precedingSalesVoucherId=' + quotationId;
    if (finalize) url += '&finalize=true';
    const data = await helpers.httpRequest({
      method: 'POST',
      url: url,
      headers: jsonHeaders,
      body: '{}'
    });
    let result = 'Invoice created from quotation successfully.';
    if (finalize) result += ' (finalized)';
    result += '\nID: ' + data.id;
    result += '\nResource: ' + data.resourceUri;
    result += '\nDeep Link: https://app.lexware.de/permalink/invoices/edit/' + data.id;
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create invoice from quotation: ' + err.message } }];
  }

// === upload_file ===
} else if (action === 'upload_file') {
  const fileBase64 = input.file_base64;
  const fileName = input.file_name || 'document.pdf';
  if (!fileBase64) return [{ json: { error: 'Parameter "file_base64" is required. Provide the file content as base64-encoded string.' } }];
  try {
    const fileBuffer = Buffer.from(fileBase64, 'base64');
    const boundary = '----n8nFormBoundary' + Date.now();
    const contentType = fileName.endsWith('.pdf') ? 'application/pdf' : fileName.endsWith('.png') ? 'image/png' : fileName.endsWith('.jpg') || fileName.endsWith('.jpeg') ? 'image/jpeg' : 'application/octet-stream';
    let bodyParts = [];
    bodyParts.push('--' + boundary);
    bodyParts.push('Content-Disposition: form-data; name="file"; filename="' + fileName + '"');
    bodyParts.push('Content-Type: ' + contentType);
    bodyParts.push('');
    const headerStr = bodyParts.join('\r\n') + '\r\n';
    const footerStr = '\r\n--' + boundary + '--\r\n';
    const headerBuf = Buffer.from(headerStr);
    const footerBuf = Buffer.from(footerStr);
    const fullBody = Buffer.concat([headerBuf, fileBuffer, footerBuf]);
    const data = await helpers.httpRequest({
      method: 'POST',
      url: baseUrl + '/files',
      headers: {
        'Authorization': 'Bearer ' + token,
        'Accept': 'application/json',
        'Content-Type': 'multipart/form-data; boundary=' + boundary
      },
      body: fullBody
    });
    return [{ json: { result: 'File uploaded successfully.\nFile ID: ' + data.id + '\nResource: ' + data.resourceUri } }];
  } catch (err) {
    return [{ json: { error: 'Failed to upload file: ' + err.message } }];
  }

// === list_vouchers ===
} else if (action === 'list_vouchers') {
  const page = input.page || '0';
  const voucherType = input.voucherType || '';
  const status = input.status || '';
  try {
    let url = baseUrl + '/voucherlist?page=' + page + '&size=25&sort=voucherDate,DESC';
    if (voucherType) url += '&voucherType=' + voucherType;
    if (status) url += '&voucherStatus=' + status;
    const data = await helpers.httpRequest({ method: 'GET', url, headers });
    if (!data.content || data.content.length === 0) {
      return [{ json: { result: 'No vouchers found.' } }];
    }
    let result = 'Vouchers (page ' + data.number + ' of ' + data.totalPages + ', ' + data.totalElements + ' total):\n\n';
    for (const v of data.content) {
      result += '**' + (v.voucherNumber || 'Draft') + '**';
      result += ' [' + v.voucherType + ']';
      result += ' — ' + (v.contactName || 'Unknown contact') + '\n';
      result += '  Date: ' + formatDate(v.voucherDate);
      result += ' | Status: ' + v.voucherStatus;
      result += ' | Total: ' + formatCurrency(v.totalAmount) + '\n';
      result += '  ID: ' + v.id + '\n\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list vouchers: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: list_articles, get_article, create_article, update_article, delete_article, list_quotations, get_quotation, create_quotation, list_invoices, get_invoice, create_invoice, create_invoice_from_quotation, upload_file, list_vouchers.' } }];
}
